final:
module RefModule(  
    input wire [2:0] in,  
    input wire [1:0] sel,  
    output wire out  
);  
    wire __out_tmp = (sel == 2'b00) ? in[0] :  
                 (sel == 2'b01) ? in[1] :  
                 (sel == 2'b10) ? in[2] :  
                 1'b0;
    assign out = __out_tmp;  
endmodule
